export type Cell = [x: number, y: number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const survives = (liveNeighbors: number): boolean =>
  liveNeighbors === 2 || liveNeighbors === 3;

const isBorn = (liveNeighbors: number): boolean => liveNeighbors === 3;

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const liveCells = new Set(cells.map(cellKey));
  const countLiveNeighbors = ([x, y]: Cell): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveCells.has(cellKey([x + dx, y + dy]))) count++;
      }
    }
    return count;
  };

  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const cell: Cell = [x + dx, y + dy];
        candidates.set(cellKey(cell), cell);
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, cell] of candidates) {
    const n = countLiveNeighbors(cell);
    if (liveCells.has(key) ? survives(n) : isBorn(n)) {
      result.push(cell);
    }
  }
  return result;
};

